/**
 * gapmax REQ-01 — n8n Code Node 1: NORMALIZE
 * Phase 1 offline filtering logic. Mode: "Run Once for All Items".
 *
 * Purpose: turn raw "Placement Data" rows (real Google Sheet) into clean, typed records
 * for the Aggregate → Threshold → Classify → Validate chain. Structural hygiene only —
 * NO aggregation, NO classification, NO business rule (those live in docs/D04_BUSINESS_RULES.md).
 *
 * Real sheet facts:
 *   - Title rows 1-2 precede the header (header on row 3).
 *   - Columns: Placement | Placement URL | Type | Network | Campaign | Impr.
 *   - Impr. arrives as string ("1.0", "1 200", "255").
 *   - Type ∈ { Mobile application, Site, YouTube video, Google products }.
 *
 * Canonical refs: docs/D04_BUSINESS_RULES.md, queries/QUERY_PACK.md.
 */

// ── Config (mirrors implementation/build/config/CONFIG_SPEC.md; no business rules here) ──
const KNOWN_TYPES = ['Mobile application', 'Site', 'YouTube video', 'Google products'];
// Column mapping adapts to whatever shape the Google Sheets read node returns —
// structural hygiene only, NO business rule (those live in docs/D04_BUSINESS_RULES.md):
//   - Read node "Header Row = 3" set  -> real headers ('Placement', 'Impr.', ...)
//   - Header Row left at default 1     -> the title row is consumed as the header, so
//     columns arrive as { '<...placement report>': colA, col_2: B, ... col_6: F }.
const REAL_COLS = {
  placement: 'Placement',
  url: 'Placement URL',
  type: 'Type',
  network: 'Network',
  campaign: 'Campaign',
  impr: 'Impr.',
};
function resolveColumns(sample) {
  // Preferred path: the real header row reached us.
  if (sample && Object.prototype.hasOwnProperty.call(sample, REAL_COLS.placement)) {
    return REAL_COLS;
  }
  // Fallback path: title row was used as header -> positional col_2..col_6, and the
  // Placement column carries the report-title key.
  const keys = sample ? Object.keys(sample) : [];
  const reportKey =
    keys.find((k) => String(k).toLowerCase().indexOf('placement report') !== -1) ||
    keys.find((k) => k !== 'row_number') ||
    REAL_COLS.placement;
  return { placement: reportKey, url: 'col_2', type: 'col_3', network: 'col_4', campaign: 'col_5', impr: 'col_6' };
}
// Assigned from the first input row in Main (kept as `let` so it can adapt at run time).
let COL = REAL_COLS;
const NONDATA_MARKERS = ['performance max placement report'];
// Date-range title row, e.g. "10 March 2026 - 16 March 2026"
const DATE_RANGE_RE = /^\d{1,2}\s+\w+\s+\d{4}\s*-\s*\d{1,2}\s+\w+\s+\d{4}$/i;

// ── Helpers ──
function clean(v) {
  return (v === undefined || v === null) ? '' : String(v).trim();
}

// "1.0" -> 1, "1 200" -> 1200, "1,200" -> 1200, "" -> null (parse failure)
function parseImpr(raw) {
  const s = clean(raw).replace(/[\s  ]/g, '').replace(/,/g, '');
  if (s === '') return null;
  const n = Number(s);
  if (!Number.isFinite(n)) return null;
  return Math.round(n);
}

function canonicalType(raw) {
  const t = clean(raw);
  if (t === '') return 'UNKNOWN';
  const hit = KNOWN_TYPES.find((k) => k.toLowerCase() === t.toLowerCase());
  return hit || 'UNKNOWN';
}

function isNonDataRow(row) {
  const placement = clean(row[COL.placement]);
  const low = placement.toLowerCase();
  if (NONDATA_MARKERS.includes(low)) return true;
  if (DATE_RANGE_RE.test(placement)) return true;
  // A stray header row that slipped through (raw read without offset).
  if (low === 'placement' && clean(row[COL.type]).toLowerCase() === 'type') return true;
  return false;
}

// ── Main ──
const input = items.map((i) => i.json);
COL = resolveColumns(input[0]); // adapt mapping to the read node's actual header shape
const summary = {
  rows_in: input.length,
  rows_out: 0,
  skipped_empty: 0,
  skipped_nondata: 0,
  impr_warnings: 0,
  normalizeWarnings: [],
  hasSiteRows: false,
  hardError: false,
};

const out = [];

for (const row of input) {
  if (isNonDataRow(row)) {
    summary.skipped_nondata += 1;
    continue;
  }

  const placement = clean(row[COL.placement]);
  let urlKey = clean(row[COL.url]).toLowerCase();
  if (urlKey === '') urlKey = placement.toLowerCase(); // fallback when URL missing

  // Empty/garbage row: no identifier at all.
  if (urlKey === '') {
    summary.skipped_empty += 1;
    continue;
  }

  const type = canonicalType(row[COL.type]);
  if (type === 'UNKNOWN') {
    summary.normalizeWarnings.push(`unknown type "${clean(row[COL.type])}" for ${urlKey}`);
  }

  const originalImpressions = clean(row[COL.impr]);
  let impressions = parseImpr(originalImpressions);
  if (impressions === null) {
    summary.impr_warnings += 1;
    summary.normalizeWarnings.push(`non-numeric Impr. "${originalImpressions}" for ${urlKey} -> 0`);
    impressions = 0;
  }
  if (impressions < 0) impressions = 0;

  if (type === 'Site') summary.hasSiteRows = true;

  out.push({
    placement,
    urlKey,
    type,
    network: clean(row[COL.network]),
    campaign: clean(row[COL.campaign]),
    originalImpressions,
    impressions,
  });
}

summary.rows_out = out.length;

// Conservation + emptiness guards.
const conserved =
  summary.rows_out + summary.skipped_empty + summary.skipped_nondata === summary.rows_in;
if (!conserved) {
  summary.hardError = true;
  summary.normalizeWarnings.push('conservation check failed (rows_out + skipped != rows_in)');
}
if (summary.rows_out === 0) {
  summary.hardError = true;
  summary.normalizeWarnings.push('no data rows after normalization');
}
if (!summary.hasSiteRows) {
  summary.normalizeWarnings.push(
    'no Type=Site rows — threshold node will be unable to compute an average'
  );
}

// n8n output: each data item carries __summary so the next node / RunLog can read it
// without a side channel. If there are zero output rows, still emit the summary.
if (out.length === 0) {
  return [{ json: { __summary: summary } }];
}
return out.map((r) => ({ json: { ...r, __summary: summary } }));

/**
 * gapmax REQ-01 — n8n Code Node 3: THRESHOLD
 * Phase 1 offline filtering logic. Mode: "Run Once for All Items".
 *
 * Purpose: compute the per-run exclusion threshold over the AGGREGATED Site population
 * (D04 Rule 1, operating on Rule-0 output). NO classification here — that is Node 4.
 *   threshold = max( SUM(impr of unique Site placements) / COUNT(unique Site placements),
 *                    IMPRESSION_FLOOR )
 * IMPRESSION_FLOOR = 500 (DEC-02; OD-1 pending). Floor prevents over-pruning when the raw
 * average is tiny (real data raw avg ≈ low tens).
 *
 * Input (from 02_aggregate.js): { placement, urlKey, type, network, impressions,
 *                                 campaignCount, campaigns, sourceRows, __summary }
 * Output: same records passed through unchanged + `threshold` attached to each, plus a
 * __summary carrying the threshold computation (for Classify + RunLog).
 *
 * Canonical refs: docs/D04_BUSINESS_RULES.md (Rules 0,1), queries/QUERY_PACK.md (Q0).
 */

// ── Config (mirrors implementation/build/config/CONFIG_SPEC.md; cites DEC-02) ──
const IMPRESSION_FLOOR = 500;
const SITE_TYPE = 'Site';

// ── Read aggregated items (drop any summary-only item) ──
const input = items.map((i) => i.json).filter((r) => r && r.urlKey);

const summary = {
  rows_in: input.length,
  rows_out: 0,
  site_count: 0,
  site_impressions: 0,
  raw_avg: 0,
  impression_floor: IMPRESSION_FLOOR,
  threshold: IMPRESSION_FLOOR,
  floor_applied: false,
  hardError: false,
  thresholdWarnings: [],
};

// ── Compute over aggregated Site placements only ──
for (const r of input) {
  if (r.type === SITE_TYPE) {
    summary.site_count += 1;
    summary.site_impressions += Number.isFinite(r.impressions) ? r.impressions : 0;
  }
}

if (summary.site_count > 0) {
  summary.raw_avg = summary.site_impressions / summary.site_count;
} else {
  summary.raw_avg = 0;
  summary.hardError = true;
  summary.thresholdWarnings.push(
    'no aggregated Site placements — cannot compute average; defaulting threshold to floor'
  );
}

summary.threshold = Math.max(summary.raw_avg, IMPRESSION_FLOOR);
summary.floor_applied = summary.threshold === IMPRESSION_FLOOR && summary.raw_avg < IMPRESSION_FLOOR;

// ── Validation (TH1–TH6) ──
const expected = Math.max(summary.raw_avg, IMPRESSION_FLOOR);
if (summary.threshold !== expected) {
  summary.hardError = true; // TH1
  summary.thresholdWarnings.push('TH1 threshold != max(raw_avg, floor)');
}
if (summary.threshold < IMPRESSION_FLOOR) {
  summary.hardError = true; // TH2
  summary.thresholdWarnings.push('TH2 threshold below floor');
}
// TH3 handled above (site_count == 0 => hardError)
if (summary.site_count > 0) {
  const expAvg = summary.site_impressions / summary.site_count;
  if (Math.abs(expAvg - summary.raw_avg) > 1e-9) {
    summary.hardError = true; // TH4
    summary.thresholdWarnings.push('TH4 raw_avg != site_impr/site_count');
  }
}

// ── Pass records through unchanged, attaching the threshold for Node 4 ──
const out = input.map((r) => ({ ...r, threshold: summary.threshold }));
summary.rows_out = out.length;

// TH5: pass-through conserves rows
if (summary.rows_out !== summary.rows_in) {
  summary.hardError = true;
  summary.thresholdWarnings.push('TH5 rows_out != rows_in (pass-through lost rows)');
}
// TH6: floor correctly applied when raw_avg < floor
if (summary.raw_avg < IMPRESSION_FLOOR && summary.threshold !== IMPRESSION_FLOOR) {
  summary.hardError = true;
  summary.thresholdWarnings.push('TH6 floor not applied when raw_avg < floor');
}

if (out.length === 0) {
  return [{ json: { __summary: summary } }];
}
return out.map((r) => ({ json: { ...r, __summary: summary } }));

/**
 * gapmax REQ-01 — n8n Code Node 4: CLASSIFY
 * Phase 1 offline filtering logic. Mode: "Run Once for All Items".
 *
 * Purpose: assign KEEP / EXCLUDE / MONITOR per the CANONICAL decision tree
 * (docs/D04_BUSINESS_RULES.md Rule 2; DEC-03 order, DEC-09/10). This node does NOT
 * define rules — it executes D04. Threshold comes from Node 3; keywords from the Sheet
 * `Unrelated keywords` tab; safeguard from the `Config` tab (OI-02 — empty = no-op).
 *
 * Decision tree (stop at first match):
 *   1. type = 'Mobile application'                                  -> EXCLUDE
 *   2. type = 'Site' + unrelated keyword + impressions >  threshold -> EXCLUDE
 *   3. type = 'Site' + unrelated keyword + impressions <= threshold -> MONITOR
 *   4. type = 'YouTube video'                                       -> KEEP (DEC-09)
 *   5. type = 'Google products'                                     -> KEEP (DEC-10)
 *   6. otherwise (incl. Site without keyword, UNKNOWN)              -> KEEP
 *   Rule 5 safeguard: a related/safeguard term present overrides EXCLUDE -> KEEP.
 *
 * Input (from 03_threshold.js): aggregated record + `threshold`.
 * Output: record + { decision, ruleTrace, matchedKeyword, safeguardApplied }.
 */

const MOBILE = 'Mobile application';
const SITE = 'Site';
const YOUTUBE = 'YouTube video';
const GOOGLE = 'Google products';

// ── Resolve keyword + safeguard lists (n8n node refs with offline fallback) ──
function resolveList(nodeName, globalKey) {
  // n8n: read from a referenced Sheets node; offline: read injected global.
  try {
    if (typeof $ === 'function') {
      const rows = $(nodeName).all().map((i) => i.json);
      const vals = [];
      for (const r of rows) {
        // Prefer a "Keywords" column (case/space-insensitive); else fall back to the first cell.
        const keyName = Object.keys(r).find((k) => String(k).trim().toLowerCase() === 'keywords');
        const v = keyName ? r[keyName] : Object.values(r)[0];
        if (v !== undefined && v !== null && String(v).trim() !== '') vals.push(String(v).trim());
      }
      if (vals.length) return vals;
    }
  } catch (e) {
    /* fall through to global */
  }
  const g = (typeof globalThis !== 'undefined' && globalThis[globalKey]) || [];
  return Array.isArray(g) ? g : [];
}

const keywords = resolveList('Read Keywords', '__KEYWORDS__').map((k) => k.toLowerCase());
const safeguard = resolveList('Read Config', '__SAFEGUARD__').map((k) => k.toLowerCase());

function firstKeyword(urlKey, list) {
  for (const term of list) {
    if (term && urlKey.includes(term)) return term;
  }
  return null;
}

// ── Read threshold-stage items ──
const input = items.map((i) => i.json).filter((r) => r && r.urlKey);

const summary = {
  rows_in: input.length,
  rows_out: 0,
  keyword_count: keywords.length,
  safeguard_count: safeguard.length,
  threshold: input.length ? input[0].threshold : null,
  counts: { KEEP: 0, EXCLUDE: 0, MONITOR: 0 },
  by_type: {},
  safeguard_overrides: 0,
  hardError: false,
  classifyWarnings: [],
};
if (safeguard.length === 0) {
  summary.classifyWarnings.push('safeguard list empty (OI-02 open) — Rule 5 is a no-op this run');
}

function classify(r) {
  const urlKey = r.urlKey;
  const threshold = r.threshold;
  let decision = 'KEEP';
  let ruleTrace = 'order-6:default-KEEP';
  let matchedKeyword = null;

  if (r.type === MOBILE) {
    decision = 'EXCLUDE';
    ruleTrace = 'order-1:Mobile application';
  } else if (r.type === SITE) {
    const kw = firstKeyword(urlKey, keywords);
    if (kw) {
      matchedKeyword = kw;
      if (r.impressions > threshold) {
        decision = 'EXCLUDE';
        ruleTrace = `order-2:Site+kw:${kw}+${r.impressions}>${threshold}`;
      } else {
        decision = 'MONITOR';
        ruleTrace = `order-3:Site+kw:${kw}+${r.impressions}<=${threshold}`;
      }
    } else {
      decision = 'KEEP';
      ruleTrace = 'order-6:Site-no-keyword';
    }
  } else if (r.type === YOUTUBE) {
    decision = 'KEEP';
    ruleTrace = 'order-4:YouTube-video-KEEP(DEC-09)';
  } else if (r.type === GOOGLE) {
    decision = 'KEEP';
    ruleTrace = 'order-5:Google-products-KEEP(DEC-10)';
  }

  // Rule 5 safeguard: override EXCLUDE -> KEEP when a safeguard term is present.
  let safeguardApplied = false;
  if (decision === 'EXCLUDE' && safeguard.length) {
    const sg = firstKeyword(urlKey, safeguard);
    if (sg) {
      decision = 'KEEP';
      ruleTrace = `safeguard:${sg}->KEEP`;
      safeguardApplied = true;
    }
  }
  return { decision, ruleTrace, matchedKeyword, safeguardApplied };
}

const out = [];
for (const r of input) {
  const c = classify(r);
  if (c.safeguardApplied) summary.safeguard_overrides += 1;
  summary.counts[c.decision] += 1;
  summary.by_type[r.type] = summary.by_type[r.type] || { KEEP: 0, EXCLUDE: 0, MONITOR: 0 };
  summary.by_type[r.type][c.decision] += 1;
  out.push({ ...r, ...c });
}
summary.rows_out = out.length;

// ── Validation (CL1–CL8) ──
const monitors = out.filter((o) => o.decision === 'MONITOR');
const checks = {
  CL1_apps_excluded: out
    .filter((o) => o.type === MOBILE)
    .every((o) => o.decision === 'EXCLUDE' || o.safeguardApplied),
  CL2_youtube_keep: out.filter((o) => o.type === YOUTUBE).every((o) => o.decision === 'KEEP'),
  CL3_google_keep: out.filter((o) => o.type === GOOGLE).every((o) => o.decision === 'KEEP'),
  CL4_monitor_below_threshold: monitors.every((o) => o.impressions <= o.threshold),
  CL5_valid_decisions: out.every((o) => ['KEEP', 'EXCLUDE', 'MONITOR'].includes(o.decision)),
  CL6_conserved: summary.rows_out === summary.rows_in,
  CL7_site_decisions_have_kw: out
    .filter((o) => o.type === SITE && (o.decision === 'EXCLUDE' || o.decision === 'MONITOR'))
    .every((o) => !!o.matchedKeyword),
  CL8_counts_sum: summary.counts.KEEP + summary.counts.EXCLUDE + summary.counts.MONITOR === summary.rows_out,
};
summary.checks = checks;
if (!Object.values(checks).every(Boolean)) {
  summary.hardError = true;
  for (const [k, v] of Object.entries(checks)) if (!v) summary.classifyWarnings.push(`FAILED ${k}`);
}

if (out.length === 0) {
  return [{ json: { __summary: summary } }];
}
return out.map((r) => ({ json: { ...r, __summary: summary } }));

/**
 * gapmax REQ-01 — n8n Code Node 5: VALIDATE
 * Phase 1 offline filtering logic. Mode: "Run Once for All Items".
 *
 * Purpose: run the V1–V9 gate checks (docs/D06_VALIDATION_PLAN.md,
 * queries/VALIDATION_QUERIES.md) over the classified placements, produce a pass/fail
 * decision + metrics for the RunLog and the IF Gate, and pass the records through so the
 * ToExclude / ToMonitor writers can split them. No re-classification — verification only.
 *
 * Input (from 04_classify.js): aggregated record + { threshold, decision, ruleTrace,
 *                              matchedKeyword, safeguardApplied, __summary }.
 * Output: each record passed through + a shared `__validation` block (checks, pass,
 *         metrics, gate) for downstream consumers.
 *
 * Canonical refs: docs/D04_BUSINESS_RULES.md, docs/D06_VALIDATION_PLAN.md.
 */

const MOBILE = 'Mobile application';
const YOUTUBE = 'YouTube video';
const GOOGLE = 'Google products';
const VALID_DECISIONS = ['KEEP', 'EXCLUDE', 'MONITOR'];

// Google Ads shared-list cap (CONFIG_SPEC EXCLUSION_CAP — confirm value, OI/OD).
const EXCLUSION_CAP =
  (typeof globalThis !== 'undefined' && Number.isFinite(globalThis.__EXCLUSION_CAP__))
    ? globalThis.__EXCLUSION_CAP__
    : 65000;
const CAP_CONFIRMED =
  typeof globalThis !== 'undefined' && Number.isFinite(globalThis.__EXCLUSION_CAP__);

const records = items.map((i) => i.json).filter((r) => r && r.urlKey);

const classifySummary = records.length ? records[0].__summary : {};
const safeguardCount = classifySummary && classifySummary.safeguard_count
  ? classifySummary.safeguard_count
  : 0;
const threshold = records.length ? records[0].threshold : null;

const excludes = records.filter((r) => r.decision === 'EXCLUDE');
const monitors = records.filter((r) => r.decision === 'MONITOR');
const keeps = records.filter((r) => r.decision === 'KEEP');

const checks = [];
function add(id, name, status, detail) {
  checks.push({ id, name, status, detail });
}

// V1 — Mobile applications classified correctly (EXCLUDE unless safeguard override)
const v1bad = records.filter(
  (r) => r.type === MOBILE && r.decision !== 'EXCLUDE' && !r.safeguardApplied
);
add('V1', 'Mobile applications -> EXCLUDE', v1bad.length === 0 ? 'PASS' : 'FAIL',
  `${records.filter((r) => r.type === MOBILE).length} apps, ${v1bad.length} mis-classified`);

// V2 — YouTube never EXCLUDE
const v2bad = records.filter((r) => r.type === YOUTUBE && r.decision === 'EXCLUDE');
add('V2', 'YouTube video never EXCLUDE', v2bad.length === 0 ? 'PASS' : 'FAIL', `${v2bad.length} violations`);

// V3 — Google products never EXCLUDE
const v3bad = records.filter((r) => r.type === GOOGLE && r.decision === 'EXCLUDE');
add('V3', 'Google products never EXCLUDE', v3bad.length === 0 ? 'PASS' : 'FAIL', `${v3bad.length} violations`);

// V4 — no MONITOR exceeds threshold
const v4bad = monitors.filter((r) => r.impressions > r.threshold);
add('V4', 'MONITOR <= threshold', v4bad.length === 0 ? 'PASS' : 'FAIL', `${v4bad.length} over threshold`);

// V5 — valid decision values only
const v5bad = records.filter((r) => !VALID_DECISIONS.includes(r.decision));
add('V5', 'valid decisions only', v5bad.length === 0 ? 'PASS' : 'FAIL', `${v5bad.length} invalid`);

// V6 — safeguard override (PENDING when OI-02 absent)
if (safeguardCount === 0) {
  add('V6', 'safeguard override', 'PENDING', 'safeguard list empty (OI-02 open) — non-blocking');
} else {
  // when present: no EXCLUDE record should still contain a safeguard term (override must have fired)
  add('V6', 'safeguard override', 'PASS', `safeguard active (${safeguardCount} terms)`);
}

// V7 — no duplicate urlKey within EXCLUDE
const exKeys = excludes.map((r) => r.urlKey);
const v7dupes = exKeys.length - new Set(exKeys).size;
add('V7', 'no duplicate urlKey in EXCLUDE', v7dupes === 0 ? 'PASS' : 'FAIL', `${v7dupes} duplicates`);

// V8 — EXCLUDE count <= cap
add('V8', 'EXCLUDE count <= cap', excludes.length <= EXCLUSION_CAP ? 'PASS' : 'FAIL',
  `exclude=${excludes.length} cap=${EXCLUSION_CAP}${CAP_CONFIRMED ? '' : ' (cap unconfirmed)'}`);

// V9 — counts reconcile with total rows
const reconcile = keeps.length + excludes.length + monitors.length === records.length;
add('V9', 'counts reconcile', reconcile ? 'PASS' : 'FAIL',
  `${keeps.length}+${excludes.length}+${monitors.length} vs ${records.length}`);

const failed = checks.filter((c) => c.status === 'FAIL');
const pending = checks.filter((c) => c.status === 'PENDING');
const pass = failed.length === 0; // PENDING is non-blocking for the gate

const metrics = {
  total: records.length,
  keep: keeps.length,
  exclude: excludes.length,
  monitor: monitors.length,
  threshold,
  exclusion_cap: EXCLUSION_CAP,
  cap_confirmed: CAP_CONFIRMED,
  keyword_count: classifySummary.keyword_count || 0,
  safeguard_count: safeguardCount,
};

const validation = {
  checks,
  pass,
  failed_ids: failed.map((c) => c.id),
  pending_ids: pending.map((c) => c.id),
  metrics,
  // Gate object the IF node reads directly.
  gate: { pass, excludeCount: excludes.length, withinCap: excludes.length <= EXCLUSION_CAP },
  runLog: {
    runDate: null, // stamped by RunLog writer (Date unavailable in this sandbox)
    ...metrics,
    pass,
    failed: failed.map((c) => c.id),
    pending: pending.map((c) => c.id),
  },
};

if (records.length === 0) {
  return [{ json: { __validation: { ...validation, pass: false, note: 'no input rows' } } }];
}
return records.map((r) => ({ json: { ...r, __validation: validation } }));

/**
 * gapmax REQ-01 — n8n Code Node 2: AGGREGATE
 * Phase 1 offline filtering logic. Mode: "Run Once for All Items".
 *
 * Purpose: collapse cross-campaign duplicates (D04 Rule 0 / DEC-11). The same placement
 * appears across multiple PMax campaigns with different impressions; the true volume is the
 * SUM across campaigns. Produces one record per unique urlKey for Threshold → Classify.
 * NO threshold, NO classification, NO business rule beyond aggregation.
 *
 * Input (from 01_normalize.js): { placement, urlKey, type, network, campaign,
 *                                 originalImpressions, impressions, __summary }
 * Canonical refs: docs/D04_BUSINESS_RULES.md (Rule 0), queries/QUERY_PACK.md.
 */

// ── Read normalized items (ignore the carried __summary; recompute our own) ──
const input = items
  .map((i) => i.json)
  .filter((r) => r && r.urlKey); // skip the summary-only item emitted when normalize had 0 rows

const summary = {
  rows_in: input.length,
  rows_out: 0,
  duplicate_rows_collapsed: 0,
  unique_placements: 0,
  total_impressions_before: 0,
  total_impressions_after: 0,
  hardError: false,
  aggregateWarnings: [],
};

// ── Group by urlKey, SUM impressions, collect unique campaigns ──
const groups = new Map();

for (const r of input) {
  const impr = Number.isFinite(r.impressions) ? r.impressions : 0;
  summary.total_impressions_before += impr;

  let g = groups.get(r.urlKey);
  if (!g) {
    g = {
      placement: r.placement,
      urlKey: r.urlKey,
      type: r.type,
      network: r.network,
      impressions: 0,
      campaignsSet: new Set(),
      sourceRows: 0,
    };
    groups.set(r.urlKey, g);
  }
  g.impressions += impr;
  g.sourceRows += 1;
  if (r.campaign) g.campaignsSet.add(r.campaign);

  // Type/network divergence across rows of the same placement: keep first, warn.
  if (g.type !== r.type) {
    summary.aggregateWarnings.push(
      `type mismatch for ${r.urlKey}: kept "${g.type}", saw "${r.type}"`
    );
  }
}

// ── Build output records ──
const out = [];
for (const g of groups.values()) {
  const campaigns = Array.from(g.campaignsSet);
  if (g.impressions < 0) g.impressions = 0;
  summary.total_impressions_after += g.impressions;
  if (g.sourceRows > 1) summary.duplicate_rows_collapsed += g.sourceRows - 1;
  out.push({
    placement: g.placement,
    urlKey: g.urlKey,
    type: g.type,
    network: g.network,
    impressions: g.impressions,
    campaignCount: campaigns.length,
    campaigns,
    sourceRows: g.sourceRows,
  });
}

summary.rows_out = out.length;
summary.unique_placements = out.length;

// ── Validation (AG1–AG6) ──
// AG1: Σ impressions conserved through aggregation
if (summary.total_impressions_before !== summary.total_impressions_after) {
  summary.hardError = true; // AG6
  summary.aggregateWarnings.push(
    `AG1/AG6 impression sum mismatch: before=${summary.total_impressions_before} after=${summary.total_impressions_after}`
  );
}
// AG2: no duplicate urlKey
const keys = out.map((o) => o.urlKey);
if (new Set(keys).size !== keys.length) {
  summary.hardError = true;
  summary.aggregateWarnings.push('AG2 duplicate urlKey in output');
}
// AG3 + AG4: per-record invariants
for (const o of out) {
  if (o.campaignCount !== new Set(o.campaigns).size) {
    summary.hardError = true;
    summary.aggregateWarnings.push(`AG3 campaignCount mismatch for ${o.urlKey}`);
  }
  if (o.sourceRows < o.campaignCount) {
    summary.hardError = true;
    summary.aggregateWarnings.push(`AG4 sourceRows<campaignCount for ${o.urlKey}`);
  }
  if (o.impressions < 0) {
    summary.hardError = true;
    summary.aggregateWarnings.push(`negative impressions for ${o.urlKey}`);
  }
}
// AG5: no output
if (summary.rows_out === 0) {
  summary.hardError = true;
  summary.aggregateWarnings.push('AG5 rows_out == 0');
}

// n8n output: aggregated items + carried __summary; emit summary-only item if empty.
if (out.length === 0) {
  return [{ json: { __summary: summary } }];
}
return out.map((r) => ({ json: { ...r, __summary: summary } }));
